function createMap(
  language: string,
  row: string,
): Record<ContentDashboardSource, string> {
  const localizedLanguage = language as LocalizedLanguage;
  const translations = [
    ...row.split("|"),
    ...EXTRA_ROWS[localizedLanguage].split("|"),
    ...DELETE_ROWS[localizedLanguage].split("|"),
    ...PAGINATION_ROWS[localizedLanguage].split("|"),
    ...HISTORY_ROWS[localizedLanguage].split("|"),
  ];
  if (translations.length !== CONTENT_DASHBOARD_SOURCE_STRINGS.length) {
    throw new Error(
      `${language} content dashboard translations must have ${CONTENT_DASHBOARD_SOURCE_STRINGS.length} entries, received ${translations.length}.`,
    );
  }

  return Object.fromEntries(
    CONTENT_DASHBOARD_SOURCE_STRINGS.map((source, index) => [
      source,
      translations[index] ?? source,
    ]),
  ) as Record<ContentDashboardSource, string>;
}

export const CONTENT_DASHBOARD_SOURCE_TRANSLATIONS = Object.fromEntries(
  Object.entries(ROWS).map(([language, row]) => [
    language,
    createMap(language, row),
  ]),
) as Record<LocalizedLanguage, Record<ContentDashboardSource, string>>;
